# MARKET INTELLIGENCE — KALSHI + POLYMARKET + COVERS
# Adds crowd/market probability as third dimension:
#   Model opinion vs Sportsbook opinion vs Public opinion
# ═══════════════════════════════════════════════════════════════

KALSHI_PATH     = os.path.join(CACHE_DIR, "kalshi_markets.json")
POLYMARKET_PATH = os.path.join(CACHE_DIR, "polymarket_markets.json")
COVERS_PATH     = os.path.join(CACHE_DIR, "covers_consensus.json")

# ── Kalshi ──────────────────────────────────────────────────────
KALSHI_SPORT_SERIES = {
    "NBA":  ["KXNBA", "NBA"],
    "MLB":  ["KXMLB", "MLB"],
    "NFL":  ["KXNFL", "NFL"],
    "NHL":  ["KXNHL", "NHL"],
    "WNBA": ["KXWNBA", "WNBA"],
}

@st.cache_data(ttl=900)
def fetch_kalshi_markets(sport="NBA"):
    """
    Fetch Kalshi prediction market probabilities for sports events.
    Kalshi = regulated prediction market, institutional money.
    
    Implied probability divergence from model = real edge signal.
    High volume Kalshi market + model disagreement = actionable.
    
    Uses ScrapeOps proxy (already integrated).
    Returns list of {event, ticker, implied_prob, volume, sport}
    """
    series = KALSHI_SPORT_SERIES.get(sport, [sport])
    results = []
    
    for series_ticker in series:
        try:
            url = f"https://api.elections.kalshi.com/trade-api/v2/markets?series_ticker={series_ticker}&limit=50&status=open"
            # Try direct first — Kalshi is less protected than Covers
            r = requests.get(url, headers={"User-Agent": "Mozilla/5.0", "Accept": "application/json"}, timeout=10)
            if r.status_code != 200 and SCRAPERAPI_KEY:
                # Use ScraperAPI (free 1k/mo) not ScrapeOps for Kalshi
                from urllib.parse import quote as _q
                r = requests.get(
                    f"http://api.scraperapi.com/?api_key={SCRAPERAPI_KEY}&url={_q(url,safe='')}",
                    timeout=15
                )
            if r.status_code != 200:
                continue
            data = r.json()
            if not isinstance(data, (dict, list)):
                st.session_state.setdefault("errors",[]).append({
                    "source":"Kalshi","error":"Unexpected response format","time":datetime.now().strftime("%H:%M")
                })
                continue
            markets = data.get("markets", data if isinstance(data, list) else [])
            if not isinstance(markets, list):
                st.session_state.setdefault("errors",[]).append({
                    "source":"Kalshi","error":f"markets field missing or wrong type: {type(markets)}","time":datetime.now().strftime("%H:%M")
                })
                continue
            for mkt in markets:
                yes_price = float(mkt.get("yes_bid", mkt.get("last_price", 50)) or 50)
                no_price  = 100 - yes_price
                volume    = int(mkt.get("volume", 0) or 0)
                if volume < 100:  # Skip illiquid markets
                    continue
                results.append({
                    "event":        mkt.get("title", mkt.get("subtitle","")),
                    "ticker":       mkt.get("ticker",""),
                    "yes_price":    yes_price,
                    "no_price":     no_price,
                    "implied_prob": round(yes_price / 100, 3),
                    "volume":       volume,
                    "sport":        sport,
                    "source":       "Kalshi",
                    "fetched_at":   datetime.now().strftime("%H:%M"),
                })
        except (requests.RequestException, ValueError, KeyError) as _ke:
            st.session_state.setdefault("errors",[]).append({"source":"Kalshi","error":str(_ke)[:80],"time":datetime.now().strftime("%H:%M")})
            continue

    if results:
        save_json_data(KALSHI_PATH, results)
    else:
        results = load_json_data(KALSHI_PATH, [])
    return results


# ── Polymarket ───────────────────────────────────────────────────
@st.cache_data(ttl=900)
def fetch_polymarket_markets(sport="NBA"):
    """
    Fetch Polymarket prediction market probabilities.
    Polymarket = decentralized, high liquidity, sophisticated traders.
    
    Returns list of {question, implied_prob, volume, sport}
    """
    sport_tags = {
        "NBA": "nba", "MLB": "mlb", "NFL": "nfl",
        "NHL": "nhl", "WNBA": "wnba",
    }
    tag = sport_tags.get(sport, sport.lower())
    
    try:
        url = f"https://gamma-api.polymarket.com/markets?active=true&tag={tag}&limit=50&order=volume&ascending=false"
        r = requests.get(url, headers={"User-Agent": "Mozilla/5.0", "Accept": "application/json"}, timeout=10)
        if r.status_code != 200:
            url2 = f"https://gamma-api.polymarket.com/markets?active=true&limit=50&tag=sports"
            r = requests.get(url2, headers={"User-Agent": "Mozilla/5.0"}, timeout=10)
        if r.status_code != 200:
            return load_json_data(POLYMARKET_PATH, [])
        
        markets = r.json()
        if isinstance(markets, dict):
            markets = markets.get("markets", markets.get("data", []))
        
        results = []
        for mkt in markets:
            # Filter for relevant sport
            tags_list = [t.lower() for t in mkt.get("tags", [])]
            if tag not in tags_list and "sports" not in tags_list:
                continue
            
            best_ask   = float(mkt.get("bestAsk", mkt.get("outcomePrices","0.5").split(",")[0].strip('" ') if "," in str(mkt.get("outcomePrices","")) else 0.5) or 0.5)
            volume     = float(mkt.get("volume", mkt.get("volumeNum", 0)) or 0)
            
            if volume < 1000:
                continue
            
            results.append({
                "question":     mkt.get("question", mkt.get("title","")),
                "slug":         mkt.get("slug",""),
                "implied_prob": round(min(0.99, max(0.01, best_ask)), 3),
                "volume":       int(volume),
                "sport":        sport,
                "source":       "Polymarket",
                "fetched_at":   datetime.now().strftime("%H:%M"),
            })
        
        results.sort(key=lambda x: -x["volume"])
        if results:
            save_json_data(POLYMARKET_PATH, results)
        return results
    except (requests.RequestException, ValueError, KeyError, json.JSONDecodeError) as _pe:
        st.session_state.setdefault("errors",[]).append({"source":"Polymarket","error":str(_pe)[:80],"time":datetime.now().strftime("%H:%M")})
        return load_json_data(POLYMARKET_PATH, [])


# ── Covers Consensus ─────────────────────────────────────────────
@st.cache_data(ttl=3600)  # 1 hour — Firecrawl credits are valuable
def fetch_covers_consensus(sport="MLB"):
    """
    Fetch Covers.com public betting consensus via Firecrawl.
    Firecrawl handles JavaScript rendering and Cloudflare bypassing.
    
    Returns list of {matchup, public_pct, side, picks, sport}
    Confirmed working: returns structured JSON with all consensus data.
    
    Requires FIRECRAWL_KEY in Streamlit secrets.
    Free tier: 500 credits/month (each scrape = 1 credit)
    """
    FIRECRAWL_KEY = st.secrets.get("FIRECRAWL_KEY", "fc-296afd1583694440938141e0bc113a38")
    if not FIRECRAWL_KEY:
        return load_json_data(COVERS_PATH, [])

    try:
        # Firecrawl interact endpoint — handles JS rendering
        url = "https://api.firecrawl.dev/v1/scrape"
        payload = {
            "url": "https://contests.covers.com/consensus",
            "formats": ["extract"],
            "extract": {
                "prompt": (
                    "Extract all rows from the consensus table. "
                    "For each row return: matchup (team names), "
                    "consensus_percentage (favorite team and %), "
                    "sides_odds (ML odds), pick_counts (number of picks per team). "
                    "Return as JSON array."
                )
            },
            "waitFor": 3000,
            "actions": [{"type": "wait", "milliseconds": 2000}],
        }
        headers = {
            "Authorization": f"Bearer {FIRECRAWL_KEY}",
            "Content-Type": "application/json",
        }
        r = requests.post(url, json=payload, headers=headers, timeout=30)
        if r.status_code != 200:
            return load_json_data(COVERS_PATH, [])

        data = r.json()
        raw = data.get("data", {})
        if isinstance(raw, dict):
            raw = raw.get("extract", raw.get("content", []))
        if isinstance(raw, str):
            import json as _json
            try:
                raw = _json.loads(raw)
            except (requests.RequestException, ValueError, KeyError):
                return load_json_data(COVERS_PATH, [])

        if not isinstance(raw, list):
            return load_json_data(COVERS_PATH, [])

        # Normalize Firecrawl response to BetCouncil schema
        results = []
        SPORT_KEYWORDS = {
            "MLB": ["royals","reds","padres","phillies","dodgers","yankees","mets","braves",
                    "cubs","sox","giants","brewers","cardinals","pirates","astros","rangers",
                    "mariners","angels","twins","tigers","guardians","orioles","rays","jays",
                    "nationals","marlins","athletics","rockies","diamondbacks"],
            "NHL": ["knights","hurricanes","bruins","maple leafs","rangers","oilers",
                    "avalanche","lightning","panthers","stars","jets","predators","blues",
                    "canucks","flames","wild","ducks","kings","sharks","sabres","senators",
                    "canadiens","flyers","penguins","capitals","devils","islanders","blackhawks","red wings","blue jackets","coyotes","kraken"],
            "NBA": ["lakers","celtics","warriors","bucks","heat","bulls","knicks","nets",
                    "76ers","suns","clippers","nuggets","jazz","spurs","pistons","pacers"],
            "WNBA": ["aces","sky","storm","mercury","fever","liberty","lynx","mystics",
                     "wings","dream","sparks","sun"],
        }

        for item in raw:
            matchup = item.get("matchup","")
            if not matchup:
                continue

            # Detect sport from team names
            matchup_lower = matchup.lower()
            detected_sport = sport  # default to requested sport
            for sp, keywords in SPORT_KEYWORDS.items():
                if any(kw in matchup_lower for kw in keywords):
                    detected_sport = sp
                    break

            # Extract consensus — find the majority side
            cons_pct = item.get("consensus_percentage", {})
            odds     = item.get("sides_odds", {})
            picks    = item.get("pick_counts", {})

            if isinstance(cons_pct, dict):
                # Find favorite (highest %)
                fav_team = max(cons_pct, key=lambda k: int(str(cons_pct[k]).replace("%","") or 0), default="")
                pub_pct  = int(str(cons_pct.get(fav_team,"50")).replace("%","") or 50)
                fav_odds = odds.get(fav_team,"")
                fav_picks= int(picks.get(fav_team, 0) or 0)
                total_picks = sum(int(v or 0) for v in picks.values())
            else:
                fav_team = ""
                pub_pct  = 50
                fav_odds = ""
                fav_picks = 0
                total_picks = 0

            results.append({
                "matchup":    matchup,
                "public_pct": pub_pct,
                "side":       fav_team,
                "odds":       fav_odds,
                "picks":      fav_picks,
                "total_picks":total_picks,
                "raw_pcts":   cons_pct,
                "sport":      detected_sport,
                "source":     "Covers",
                "fetched_at": datetime.now().strftime("%H:%M"),
            })

        if results:
            save_json_data(COVERS_PATH, results)
        return results

    except (requests.RequestException, ValueError, KeyError, json.JSONDecodeError) as _ce:
        st.session_state.setdefault("errors",[]).append({"source":"Covers","error":str(_ce)[:80],"time":datetime.now().strftime("%H:%M")})
        return load_json_data(COVERS_PATH, [])


# ── Market Consensus Engine ──────────────────────────────────────
def compute_market_consensus(model_prob, player, prop, sport, game_analysis=None):
    """
    Compare model probability vs prediction market probabilities.
    
    Divergence signal:
      Model > Markets by 5%+  → Model bullish, markets disagree → value
      Model < Markets by 5%+  → Model bearish, markets disagree → fade
      Agreement               → Market efficient, lower confidence

    Returns dict with consensus, divergence, signal, source breakdown.
    """
    market_probs = []
    sources = []
    
    # Pull from session state (already fetched)
    kalshi_data   = st.session_state.get("kalshi_markets", [])
    poly_data     = st.session_state.get("polymarket_markets", [])
    covers_data   = st.session_state.get("covers_consensus", [])
    
    player_lower = normalize_name(player)
    
    # Build normalized name tokens for exact matching
    player_tokens = set(normalize_name(player).split())
    
    # Use single list of {prob, volume} to guarantee alignment
    market_entries = []

    # Pre-build Kalshi/Poly indexes if not cached — avoids O(N×M) scan
    if "_kalshi_idx" not in st.session_state or len(st.session_state["_kalshi_idx"]) != len(kalshi_data):
        _ki = {}
        for _m in kalshi_data:
            for _t in set(normalize_name(_m.get("event","")).split()):
                _ki.setdefault(_t,[]).append(_m)
        st.session_state["_kalshi_idx"] = _ki
    if "_poly_idx" not in st.session_state or len(st.session_state["_poly_idx"]) != len(poly_data):
        _pi = {}
        for _m in poly_data:
            for _t in set(normalize_name(_m.get("question","")).split()):
                _pi.setdefault(_t,[]).append(_m)
        st.session_state["_poly_idx"] = _pi
    _kalshi_idx = st.session_state["_kalshi_idx"]
    _poly_idx   = st.session_state["_poly_idx"]

    # Match Kalshi markets — require ALL first+last name tokens to match
    for mkt in kalshi_data:
        event_tokens = set(normalize_name(mkt.get("event","")).split())
        matched = (len(player_tokens) >= 2 and player_tokens.issubset(event_tokens)) or                   (len(player_tokens) == 1 and player_tokens.issubset(event_tokens))
        if matched:
            market_entries.append({
                "prob":   mkt["implied_prob"],
                "volume": float(mkt.get("volume", 1000)),
                "source": f"Kalshi({mkt['implied_prob']:.0%})",
            })
    
    # Match Polymarket — exact token matching
    for mkt in poly_data:
        q_tokens = set(normalize_name(mkt.get("question","")).split())
        matched = len(player_tokens) >= 2 and player_tokens.issubset(q_tokens)
        if matched:
            market_entries.append({
                "prob":   mkt["implied_prob"],
                "volume": float(mkt.get("volume", 1000)),
                "source": f"Polymarket({mkt['implied_prob']:.0%})",
            })

    # Match Covers consensus — by team name not sport string
    covers_game = None
    if covers_data:
        home_t = (game_analysis or {}).get("home","") if game_analysis else ""
        away_t = (game_analysis or {}).get("away","") if game_analysis else ""
        for _cd in covers_data:
            _cd_matchup = _cd.get("matchup","").lower()
            # Match by actual team names, not sport code
            if home_t and away_t:
                if (home_t.lower()[:4] in _cd_matchup or
                    away_t.lower()[:4] in _cd_matchup):
                    covers_game = _cd
                    break
            elif home_t and home_t.lower()[:4] in _cd_matchup:
                covers_game = _cd
                break

    if not market_entries:
        return None

    # Volume-weighted average — guaranteed alignment via single list
    total_vol = sum(e["volume"] for e in market_entries)
    sources   = [e["source"] for e in market_entries]
    consensus_prob = (
        sum(e["prob"] * e["volume"] for e in market_entries) / total_vol
        if total_vol > 0
        else sum(e["prob"] for e in market_entries) / len(market_entries)
    )
    market_probs = [e["prob"] for e in market_entries]
    divergence     = model_prob - consensus_prob
    
    if divergence >= 0.08:
        signal = "MODEL_BULLISH"
        note   = f"📈 Model {model_prob:.0%} vs Markets {consensus_prob:.0%} — strong value"
        adj    = min(0.04, divergence * 0.40)  # up to +4% edge boost
    elif divergence >= 0.04:
        signal = "MODEL_LEAN_BULLISH"
        note   = f"📊 Model {model_prob:.0%} vs Markets {consensus_prob:.0%} — mild value"
        adj    = min(0.02, divergence * 0.30)
    elif divergence <= -0.08:
        signal = "MARKET_BULLISH"
        note   = f"📉 Markets {consensus_prob:.0%} vs Model {model_prob:.0%} — fade signal"
        adj    = max(-0.04, divergence * 0.40)
    else:
        signal = "AGREEMENT"
        note   = f"✅ Model ≈ Markets ({consensus_prob:.0%}) — efficient"
        adj    = 0.0
    
    return {
        "consensus_prob":  round(consensus_prob, 3),
        "model_prob":      round(model_prob, 3),
        "divergence":      round(divergence, 3),
        "signal":          signal,
        "note":            note,
        "edge_adj":        round(adj, 3),
        "sources":         sources,
    }


# ── Covers Public Fade Signal ────────────────────────────────────
def compute_sharp_public_divergence(matchup, public_betting=None):
    """
    Full sharp/public divergence with RLM detection.
    Replaces the basic sharp signal detection.
    """
    if public_betting is None:
        public_betting = st.session_state.get("public_betting", {})
    pb_data = None
    for key, val in public_betting.items():
        teams = val.get("teams", [])
        if any(t.lower() in matchup.lower() for t in teams if t):
            pb_data = val
            break
    if not pb_data:
        return {}
    sharp_sigs = pb_data.get("sharp_signals", [])
    rlm_sigs   = pb_data.get("rlm_signals",   [])
    result = {
        "sharp_signals": sharp_sigs,
        "rlm_signals":   rlm_sigs,
        "has_sharp":     len(sharp_sigs) > 0,
        "has_rlm":       len(rlm_sigs) > 0,
        "max_strength":  max((r.get("strength",0) for r in rlm_sigs), default=0),
        "ml_data":       pb_data.get("ml",{}),
        "spread_data":   pb_data.get("spread",{}),
        "total_data":    pb_data.get("total",{}),
    }
    strength = result["max_strength"]
    result["edge_adj"] = round(0.02 if strength >= 3 else 0.01 if strength >= 2 else 0.005 if strength >= 1 else 0, 3)
    return result


def format_rlm_display(rlm_data):
    """Format RLM/sharp signal for prop card Why section."""
    if not rlm_data or not rlm_data.get("has_sharp"):
        return ""
    lines = []
    for sig in rlm_data.get("sharp_signals", [])[:2]:
        lines.append(sig)
    for rlm in rlm_data.get("rlm_signals", [])[:1]:
        lines.append(
            f"↔️ RLM: {rlm.get('public_pct',0)}% tickets on {rlm.get('public_side','')} | "
            f"{rlm.get('money_pct',0)}% money on {rlm.get('sharp_side','')} — sharp action detected"
        )
    return " | ".join(lines)


def compute_public_fade_signal(matchup, sport, model_pick_side):
    """
    Public Fade: when 70%+ of public bets on one side,
    sharps are often on the other side.
    
    Strong signal when:
      public_pct >= 75% AND model agrees with MINORITY → contrarian bet
      public_pct >= 75% AND model agrees with MAJORITY → proceed with caution
    
    Returns: {public_pct, side, fade_signal, note}
    """
    covers_data = st.session_state.get("covers_consensus", [])
    if not covers_data:
        return None
    
    matchup_lower = matchup.lower()
    for item in covers_data:
        item_matchup = item.get("matchup","").lower()
        # Fuzzy match
        if any(w in item_matchup for w in matchup_lower.split(" @ ")):
            public_pct = item.get("public_pct", 50)
            public_side = item.get("side","")
            
            if public_pct >= 75:
                if public_side.lower() not in str(model_pick_side).lower():
                    # Model agrees with MINORITY → contrarian signal
                    return {
                        "public_pct":  public_pct,
                        "side":        public_side,
                        "fade_signal": "CONTRARIAN",
                        "note":        f"🎯 Fade: {public_pct}% public on {public_side}, model takes minority",
                        "edge_adj":    0.02,  # +2% contrarian boost
                    }
                else:
                    # Model with the public → fade warning
                    return {
                        "public_pct":  public_pct,
                        "side":        public_side,
                        "fade_signal": "WITH_PUBLIC",
                        "note":        f"⚠️ {public_pct}% public on {public_side} — is this a trap?",
                        "edge_adj":    -0.01,  # -1% public side penalty
                    }
            elif public_pct >= 60:
                return {
                    "public_pct":  public_pct,
                    "side":        public_side,
                    "fade_signal": "MILD_PUBLIC",
                    "note":        f"📊 {public_pct}% public on {public_side}",
                    "edge_adj":    0.0,
                }
    return None


