# MODULE: OCR — bet screenshot parsing
# Future extraction target: ocr.py
# ═══════════════════════════════════════════════════════════
def parse_bet_screenshot_ocr(image_bytes):
    """
    Parse PrizePicks/prop screenshots using Claude vision API.
    Replaces pytesseract OCR — no local Tesseract install needed.
    """
    import base64 as _b64, json as _json, io, re
    try:
        # Try Claude vision first (most accurate)
        img_b64 = _b64.b64encode(image_bytes).decode()

        # Detect image format
        from PIL import Image as _PIL
        _img = _PIL.open(io.BytesIO(image_bytes))
        fmt  = (_img.format or "PNG").lower()
        if fmt == "jpeg": fmt = "jpeg"
        elif fmt == "webp": fmt = "webp"
        else: fmt = "png"
        media_type = f"image/{fmt}"

        # Call Claude vision
        api_resp = requests.post(
            "https://api.anthropic.com/v1/messages",
            headers={
                "x-api-key":         st.secrets.get("ANTHROPIC_API_KEY",""),
                "anthropic-version": "2023-06-01",
                "content-type":      "application/json",
            },
            json={
                "model": "claude-opus-4-5",
                "max_tokens": 1024,
                "messages": [{
                    "role": "user",
                    "content": [
                        {
                            "type": "image",
                            "source": {
                                "type":       "base64",
                                "media_type": media_type,
                                "data":       img_b64,
                            }
                        },
                        {
                            "type": "text",
                            "text": """Extract all player props from this betting slip image.
Return ONLY a JSON array, no other text, like this:
[
  {"player": "Nikola Jokic", "prop": "Points", "line": 27.5, "side": "OVER", "sport": "NBA"},
  {"player": "Jayson Tatum", "prop": "Rebounds", "line": 8.5, "side": "OVER", "sport": "NBA"}
]

Rules:
- Extract every player prop shown
- side is OVER or UNDER (MORE=OVER, LESS=UNDER)
- line is a number
- sport: NBA, MLB, NHL, NFL, or WNBA
- If sport unclear, use NBA
- Include only active/pending props, skip settled ones
- Return empty array [] if no props found"""
                        }
                    ]
                }]
            },
            timeout=30
        )

        if api_resp.status_code == 200:
            content = api_resp.json().get("content", [{}])[0].get("text","")
            st.session_state["ocr_raw_text"] = content
            # Parse JSON from response
            clean = content.strip()
            if "```" in clean:
                clean = re.sub(r"```[a-z]*", "", clean).replace("```","").strip()
            picks = _json.loads(clean)
            result = []
            for p in picks:
                player = str(p.get("player","")).strip()
                prop   = str(p.get("prop","")).strip()
                line   = p.get("line",0)
                side   = str(p.get("side","OVER")).upper()
                sport  = str(p.get("sport","NBA")).upper()
                if player and prop and line:
                    result.append({
                        "player": player,
                        "prop":   prop,
                        "line":   float(line),
                        "side":   side,
                        "sport":  sport,
                        "book":   "PrizePicks",
                    })
            return result
        else:
            # Fallback to pytesseract if Claude fails
            raise Exception(f"Claude API error: {api_resp.status_code}")

    except Exception as e:
        # Fallback: try pytesseract
        try:
            import pytesseract
            from PIL import Image, ImageEnhance, ImageOps
            img = _PIL.open(io.BytesIO(image_bytes)).convert("RGB")
            w, h = img.size
            scale = 3 if max(w,h) < 1200 else 2
            img_proc = img.resize((w*scale,h*scale), _PIL.LANCZOS).convert("L")
            img_proc = ImageOps.invert(img_proc)
            img_proc = ImageEnhance.Contrast(img_proc).enhance(3.0)
            raw = pytesseract.image_to_string(img_proc, config="--psm 6 --oem 3")
            st.session_state["ocr_raw_text"] = raw
            # Basic parse
            result = []
            for line in raw.split("\n"):
                m = re.search(r"([A-Za-z][A-Za-z .\'-]+)\s+(OVER|UNDER|MORE|LESS)\s+([\d.]+)", line, re.I)
                if m:
                    side = "OVER" if m.group(2).upper() in ("OVER","MORE") else "UNDER"
                    result.append({
                        "player": m.group(1).strip(),
                        "prop":   "Points",
                        "line":   float(m.group(3)),
                        "side":   side,
                        "sport":  "NBA",
                        "book":   "PrizePicks",
                    })
            return result
        except Exception as e2:
            st.session_state.setdefault("errors",[]).append({
                "time":   datetime.now().strftime("%H:%M:%S"),
                "source": "parse_bet_screenshot_ocr",
                "error":  str(e2)[:150],
            })
            return []


def parse_prizepicks_text(raw_text):
    """Parse the copy-paste text block format from PrizePicks results.

    Expected repeating block (12 lines per player):
      Player Name
      Position (G / IF / OF / C-F / etc.)
      Sport (NBA / MLB / NHL / etc.)
      Team abbreviation
      Team score
      vs  (or @)
      Opp team
      Opp score
      Final  (or Live / Pending)
      Line  (e.g. 1.5)
      Stat type  (e.g. Hits+Runs+RBIs)
      Actual result  (numeric)
    """
    import re

    POSITIONS = {"G", "F", "C", "IF", "OF", "P", "SP", "RP", "C-F", "G-F", "F-C", "PG", "SG", "SF", "PF"}
    SPORTS    = {"NBA", "MLB", "NHL", "NFL", "WNBA", "NCAAB", "NCAAF", "MLS", "EPL", "PGA"}

    rows = [l.strip() for l in raw_text.strip().split("\n") if l.strip()]
    bets = []
    i = 0

    while i < len(rows):
        # Need at least 12 lines ahead to form a full block
        if i + 11 >= len(rows):
            i += 1
            continue

        player   = rows[i]
        pos      = rows[i + 1].upper()
        sport    = rows[i + 2].upper()

        if pos not in POSITIONS or sport not in SPORTS:
            i += 1
            continue

        # Slots i+3 … i+11
        team_score_raw = rows[i + 4]   # team score (may be int)
        status         = rows[i + 8]   # "Final", "Live", etc.
        line_raw       = rows[i + 9]
        stat_type      = rows[i + 10]
        result_raw     = rows[i + 11]

        try:
            line_val   = float(line_raw)
            result_val = float(result_raw)
        except ValueError:
            i += 1
            continue

        # Determine outcome based on side
        status_upper = status.upper()
        if any(w in status_upper for w in ("LIVE", "PENDING", "PROGRESS", "SCHEDULED")):
            outcome = "PENDING"
        else:
            # For UNDER picks, winning means result < line
            if side == "UNDER":
                outcome = "WIN" if result_val < line_val else "LOSS"
            else:
                outcome = "WIN" if result_val > line_val else "LOSS"

        bets.append({
            "player":     player,
            "prop":       stat_type,
            "line":       line_val,
            "side":       "OVER",   # default; user can override in confirm UI
            "sport":      sport,
            "outcome":    outcome,
            "result":     result_val,
            "wager":      0,
            "pick_count": 2,
            "source":     "PrizePicks",
            "bet_type":   "prop",
        })
        i += 12

    return bets

