def compute_multi_signal_edge(  # Calculates edge using 12 weighted signals (Base, Def, Loc, Rest, Pace + overlays)
line, player_avg, opp_def_rating, is_home, teammate_out_boost, side="OVER", stat_key="PTS", pace_adj=0.0, days_rest=2, odds_type="standard", sport="NBA", std_dev=None, weights=None, player_name=""):
    if player_avg <= 0:
        return 0.0, 0.5, {}
    signals = {}
    league_avg_def = 112.0
    if weights is None:
        # Load optimizer weights once per session — cached in session_state
        # Avoids 50+ disk reads per board load (one per prop)
        _cache_key = f"_opt_weights_{sport}"
        if _cache_key not in st.session_state:
            from_optimizer = load_json_data(WEIGHT_OPTIMIZER_PATH, {})
            sport_optimizer = from_optimizer.get(sport, {})
            if (sport_optimizer.get("weights") and sport_optimizer.get("n_bets", 0) >= WEIGHT_OPTIMIZER_MIN_BETS):
                st.session_state[_cache_key] = sport_optimizer["weights"]
            else:
                st.session_state[_cache_key] = SPORT_SIGNAL_WEIGHTS.get(sport, SPORT_SIGNAL_WEIGHTS["NBA"])
        weights = st.session_state[_cache_key]
    if stat_key in ["HR", "GOALS"]:
        prob = poisson_prob_over(line, player_avg)
        if side.upper() == "UNDER":
            prob = 1 - prob
        base_edge = calculate_edge(prob, side, sport)
        fair_prob = prob
    else:
        fair_prob = compute_fair_prob(line, player_avg, std_dev, side)
        base_edge = compute_market_edge(fair_prob, side)
    signals["base"] = base_edge
    signals["fair_prob_base"] = fair_prob
    signals["model_prob"] = fair_prob
    signals["consensus_prob"] = None
    signals["consensus_books"] = []
    if opp_def_rating > 0:
        def_adj = (opp_def_rating - league_avg_def) / league_avg_def
        signals["defense"] = (-def_adj * weights.get("defense", 0.30) if side.upper() == "OVER" else def_adj * weights.get("defense", 0.30))
    else:
        signals["defense"] = 0
    # Apply regime adjustments (early season / playoffs)
    _regime = detect_season_regime(sport)
    if _regime.get("adjustments"):
        for _rsig, _radj in _regime["adjustments"].items():
            if _rsig in signals:
                signals[_rsig] = round(signals.get(_rsig, 0) + _radj, 4)

    # Player-specific home/away split — falls back to global constant
    _splits = PLAYER_HOME_SPLITS.get(
        next((k for k in PLAYER_HOME_SPLITS if normalize_name(k) == normalize_name(player_name)), ""),
        None
    )
    if _splits:
        location_adj = _splits["home"] if is_home else _splits["away"]
    else:
        location_adj = GLOBAL_HOME_ADJ if is_home else GLOBAL_AWAY_ADJ
    if side.upper() == "UNDER":
        location_adj = -location_adj
    signals["location"] = location_adj
    # Continuous rest model — 5 levels vs binary 0/other
    # Research basis: NBA performance degrades ~8% on B2B,
    # ~3% on 1-day rest, neutral at 2 days, slight boost 3+
    if days_rest == 0:
        rest_adj = -0.08   # back-to-back: significant fatigue
    elif days_rest == 1:
        rest_adj = -0.03   # short rest: mild fatigue
    elif days_rest == 2:
        rest_adj = 0.0     # standard rest: neutral
    elif days_rest == 3:
        rest_adj = 0.01    # extra rest: slight boost
    else:
        rest_adj = 0.02    # 4+ days rest: well-rested boost
    signals["rest"] = rest_adj
    signals["pace"] = pace_adj if side.upper() == "OVER" else -pace_adj
    combined = (signals["base"] * weights.get("base", 0.45) + signals["defense"] * weights.get("defense", 0.30) + signals["location"] * weights.get("location", 0.15) + signals["rest"] * weights.get("rest", 0.05) + signals["pace"] * weights.get("pace", 0.05))
    if teammate_out_boost:
        # Usage signal now governed by weights framework — optimizer can tune it
        # Default weight 0.74 matches prior behavior; optimizer will adjust from data
        usage_weight = weights.get("usage", 0.74)
        usage_signal = teammate_out_boost * usage_weight
        combined += usage_signal
        signals["usage"] = usage_signal
    else:
        signals["usage"] = 0.0
    if odds_type == "demon":
        combined *= 0.85
    elif odds_type == "goblin":
        combined *= 1.10
    combined = max(-EDGE_CAP, min(EDGE_CAP, combined))
    base_prob = signals.get("fair_prob_base", 0.524)
    signal_adjustment = combined - signals.get("base", 0)
    prob = base_prob + signal_adjustment
    prob = max(0.20, min(0.80, prob))
    return combined, prob, signals

def make_display_df(props):
    """Convert raw enriched prop dicts into a clean display DataFrame with friendly column names."""
    rows = []
    for p in props:
        rows.append({
            "Player":         p.get("Player", ""),
            "Stat":           p.get("Prop", ""),
            "Line":           p.get("Line", ""),
            "Play":           f"{p.get('Side','OVER')} {p.get('Line','')}",
            "Avg (10g)":      round(p.get("Avg", 0), 1) if p.get("Avg") else "—",
            "Fair %":         p.get("ModelProb", "—"),
            "Edge":           p.get("EdgePct", "—"),
            "2-Pick EV":      p.get("EV_2pick", "—"),
            "Bet Size":       f"${p.get('Wager_2pick', p.get('Wager', 0)):.2f}",
            "Tier":           p.get("Tier", "—"),
            "AN Grade":       p.get("AN_Grade", "—"),
            "AN Proj":        p.get("AN_Projection", "—"),
            "AN Tier":        p.get("AN_Tier", "—"),
            "AN Confirms":    "✅" if p.get("AN_Confirms") else "—",
            "Line Fair?":     p.get("FairnessGrade", "—"),
            "Sharp $":        p.get("SharpFlag", "—"),
            "Market":         p.get("Efficiency", "—"),
            "Confidence":     p.get("ConfidenceMult", "—"),
            "Injury":         p.get("Injury", ""),
            "Line Move":      p.get("Movement", "—"),
            "Trend":          p.get("Trend", "—"),
            "Source":         p.get("source", "—"),
            "Consensus Prob": p.get("ConsensusProb", "—"),
            "Books":          p.get("ConsensusBooks", "—"),
            "Best Alt Line":  p.get("BestAltLine", "—"),
            "Alt EV":         p.get("BestAltEV", "—"),
            "Alt Payout":     p.get("BestAltPayout", "—"),
            "SEM":            p.get("SEM", "—"),
            "CLV Adj":        p.get("CLVAdj", "—"),
            "Side":           p.get("Side", "OVER"),
            "Prop":           p.get("Prop", ""),
        })
    return pd.DataFrame(rows)

def fetch_dk_salaries(sport="NBA"):
    """
    Fetch DraftKings DFS salary data for today's slate.
    Returns dict: {player_name: {salary, avg_points, value_score}}
    High salary = DK model projects big game
    Value score = projected points per $1000 salary
    """
    cache_path = os.path.join(CACHE_DIR, f"dk_salaries_{sport}.pkl")
    if os.path.exists(cache_path):
        age_mins = (time.time() - os.path.getmtime(cache_path)) / 60
        if age_mins < 90:
            with open(cache_path, "rb") as f:
                return pickle.load(f)

    sport_map = {
        "NBA": "NBA", "MLB": "MLB", "NHL": "NHL",
        "NFL": "NFL", "WNBA": "WNBA"
    }
    dk_sport = sport_map.get(sport)
    if not dk_sport:
        return {}

    try:
        # Step 1: get draftGroupId
        contests_r = requests.get(
            f"https://www.draftkings.com/lobby/getcontests?sport={dk_sport}",
            headers={**HEADERS, "Referer": "https://www.draftkings.com/"},
            timeout=10
        )
        if contests_r.status_code != 200:
            return {}

        contests = contests_r.json().get("Contests", [])
        draft_group_id = None
        for c in contests:
            name = c.get("n", "").lower()
            if ("classic" in name or "showdown" not in name) and c.get("dg"):
                draft_group_id = c["dg"]
                break

        if not draft_group_id:
            return {}

        # Step 2: get draftable players with salaries
        players_r = requests.get(
            f"https://api.draftkings.com/draftgroups/v1/{draft_group_id}/draftables",
            headers={**HEADERS, "Referer": "https://www.draftkings.com/"},
            timeout=10
        )
        if players_r.status_code != 200:
            return {}

        data = players_r.json()
        draftables = data.get("draftables", [])

        salaries = {}
        for player in draftables:
            name = player.get("displayName", "")
            salary = player.get("salary", 0)
            avg_pts = player.get("draftStatAttributes", [{}])
            # Extract average FPPG
            fppg = 0.0
            for attr in player.get("draftStatAttributes", []):
                if attr.get("id") == 90:  # FPPG stat id
                    try:
                        fppg = float(attr.get("value", 0))
                    except Exception:
                        pass

            if name and salary:
                value_score = round((fppg / (salary / 1000)), 2) if salary > 0 else 0
                salaries[normalize_name(name)] = {
                    "name": name,
                    "salary": salary,
                    "fppg": fppg,
                    "value": value_score,
                    "salary_tier": (
                        "ELITE" if salary >= 9000 else
                        "HIGH" if salary >= 7500 else
                        "MID" if salary >= 6000 else
                        "VALUE"
                    )
                }

        if salaries:
            with open(cache_path, "wb") as f:
                pickle.dump(salaries, f)
            st.session_state["dk_salaries"] = salaries

        return salaries

    except Exception as e:
        st.session_state.setdefault("errors", []).append({
            "time": datetime.now().strftime("%H:%M:%S"),
            "source": "fetch_dk_salaries",
            "error": str(e)[:100]
        })
        return {}


def apply_dk_salary_signal(prop, dk_salaries):
    """
    Apply DraftKings salary as a signal modifier.
    High salary = market confidence signal
    Returns signal adjustment (-0.05 to +0.05)
    """
    if not dk_salaries:
        return 0.0, ""

    norm = normalize_name(prop.get("Player", ""))
    dk_data = dk_salaries.get(norm)
    if not dk_data:
        return 0.0, ""

    salary = dk_data["salary"]
    tier = dk_data["salary_tier"]
    value = dk_data["value"]
    fppg = dk_data["fppg"]

    # High salary + high value = positive signal
    # High salary + low value = cautious (might be overpriced)
    if tier == "ELITE" and value >= 5.0:
        return 0.02, f"DK Elite ${salary:,} | {fppg:.1f} FPPG | {value:.1f}x value"
    elif tier == "ELITE":
        return 0.01, f"DK Elite ${salary:,} | {fppg:.1f} FPPG"
    elif tier == "HIGH" and value >= 5.5:
        return 0.015, f"DK High ${salary:,} | {fppg:.1f} FPPG | {value:.1f}x value"
    elif tier == "VALUE" and value >= 6.0:
        return 0.02, f"DK Value ${salary:,} | {fppg:.1f} FPPG | {value:.1f}x VALUE PLAY"
    else:
        return 0.0, f"DK ${salary:,} | {tier}"


# =============================================================
# PINNACLE FAIR VALUE ENGINE
# The gold standard: use Pinnacle no-vig odds as true probability
# Elite models (OddsJam, Outlier, Sharp) all anchor to Pinnacle
# =============================================================

PINNACLE_PROP_CACHE = {}  # in-memory: {(player_norm, stat, line): {"over_prob": x, "under_prob": x}}
PINNACLE_GAME_CACHE = {}  # in-memory: {(home, away, market): {"prob": x, "line": x}}

@st.cache_data(ttl=900)
def fetch_pinnacle_lines(sport):
    """
    Fetch Pinnacle lines via OddsPAPI (already in our stack).
    Cache in session state — only 1 API call per board load per sport.
    Respects free tier: 100 calls/day, 1000/month.
    """
    cache_key = f"pinnacle_{sport}"
    if st.session_state.get(cache_key):
        return st.session_state[cache_key]

    # Check disk cache first — 60 min TTL for Pinnacle lines
    cache_path = os.path.join(CACHE_DIR, f"pinnacle_lines_{sport}.pkl")
    if os.path.exists(cache_path):
        age_mins = (time.time() - os.path.getmtime(cache_path)) / 60
        if age_mins < 60:
            with open(cache_path, "rb") as f:
                cached = pickle.load(f)
            if cached:
                st.session_state[cache_key] = cached
                return cached

    if not ODDSPAPI_KEY:
        return {}

    allowed, reason = api_budget_check("ODDSPAPI")
    if not allowed:
        return {}

    sport_id_map = {"NBA": 4, "WNBA": 4, "MLB": 3, "NHL": 6, "NFL": 1}
    sport_id = sport_id_map.get(sport)
    if not sport_id:
        return {}

    pinnacle_data = {"props": {}, "games": {}}

    try:
        # Get tournaments
        t_resp = requests.get(
            f"https://api.oddspapi.io/v4/tournaments?sportId={sport_id}&apiKey={ODDSPAPI_KEY}",
            timeout=10
        )
        if t_resp.status_code != 200:
            return {}

        tournaments = t_resp.json()
        top_ids = [str(t["tournamentId"]) for t in tournaments
                   if t.get("upcomingFixtures", 0) > 0][:3]
        if not top_ids:
            top_ids = [str(t["tournamentId"]) for t in tournaments[:2]]
        if not top_ids:
            return {}

        tournament_ids = ",".join(top_ids)

        # Fetch Pinnacle ONLY — saves API credits vs fetching all books
        resp = requests.get(
            f"https://api.oddspapi.io/v4/odds-by-tournaments"
            f"?bookmaker=pinnacle&tournamentIds={tournament_ids}"
            f"&apiKey={ODDSPAPI_KEY}&oddsFormat=american",
            headers=HEADERS,
            timeout=15
        )
        api_budget_increment("ODDSPAPI")

        if resp.status_code != 200:
            return {}

        data = resp.json()

        for event in data.get("events", []):
            home = event.get("home_team", "")
            away = event.get("away_team", "")
            for bookmaker in event.get("bookmakers", []):
                if bookmaker.get("key", "").lower() != "pinnacle":
                    continue
                for market in bookmaker.get("markets", []):
                    mkey = market.get("key", "")
                    outcomes = market.get("outcomes", [])

                    # Player props
                    if "player" in mkey.lower():
                        over_out = next((o for o in outcomes if o.get("name","").upper() == "OVER"), None)
                        under_out = next((o for o in outcomes if o.get("name","").upper() == "UNDER"), None)
                        if over_out and under_out:
                            over_imp = devig_odds(over_out.get("price"))
                            under_imp = devig_odds(under_out.get("price"))
                            if over_imp and under_imp:
                                total = over_imp + under_imp
                                over_nv = round(over_imp / total, 4)
                                under_nv = round(under_imp / total, 4)
                                player = over_out.get("description", "")
                                line = over_out.get("point")
                                stat = mkey.replace("player_","").replace("_"," ").title()
                                if player and line is not None:
                                    pkey = (normalize_name(player), stat.lower(), float(line))
                                    pinnacle_data["props"][pkey] = {
                                        "over_prob": over_nv,
                                        "under_prob": under_nv,
                                        "over_odds": over_out.get("price"),
                                        "under_odds": under_out.get("price"),
                                        "player": player, "stat": stat, "line": float(line)
                                    }

                    # Game lines
                    elif mkey in ("h2h", "spreads", "totals"):
                        if len(outcomes) >= 2:
                            imp_a = devig_odds(outcomes[0].get("price"))
                            imp_b = devig_odds(outcomes[1].get("price"))
                            if imp_a and imp_b:
                                total = imp_a + imp_b
                                prob_a = round(imp_a / total, 4)
                                game_key = (normalize_name(home), normalize_name(away), mkey)
                                pinnacle_data["games"][game_key] = {
                                    "prob_home": prob_a,
                                    "prob_away": round(imp_b / total, 4),
                                    "line_home": outcomes[0].get("point"),
                                    "line_away": outcomes[1].get("point"),
                                    "odds_home": outcomes[0].get("price"),
                                    "odds_away": outcomes[1].get("price"),
                                }

        # Cache to disk and session
        with open(cache_path, "wb") as f:
            pickle.dump(pinnacle_data, f)
        st.session_state[cache_key] = pinnacle_data
        n_props = len(pinnacle_data["props"])
        n_games = len(pinnacle_data["games"])
        return pinnacle_data

    except Exception as e:
        st.session_state.setdefault("errors", []).append({
            "time": datetime.now().strftime("%H:%M:%S"),
            "source": "fetch_pinnacle_lines",
            "error": str(e)[:100]
        })
        return {}


def pinnacle_fair_value(player, stat, line, side="OVER", sport="NBA"):
    """
    Get Pinnacle no-vig true probability for a prop.
    Returns (prob, confirms_model, note) or (None, False, "")
    """
    cache_key = f"pinnacle_{sport}"
    pinn_data = st.session_state.get(cache_key, {})
    if not pinn_data:
        return None, False, ""

    props = pinn_data.get("props", {})
    norm_player = normalize_name(player)
    norm_stat = stat.lower().replace(" ","_").replace("+","_")

    # Try exact match first
    pkey = (norm_player, stat.lower(), float(line))
    entry = props.get(pkey)

    # Try fuzzy stat match
    if not entry:
        for k, v in props.items():
            if k[0] == norm_player and abs(k[2] - float(line)) <= 0.5:
                stat_match = (
                    stat.lower()[:4] in k[1].lower() or
                    k[1].lower()[:4] in stat.lower()
                )
                if stat_match:
                    entry = v
                    break

    if not entry:
        return None, False, ""

    prob = entry["over_prob"] if side == "OVER" else entry["under_prob"]
    over_odds = entry.get("over_odds")
    under_odds = entry.get("under_odds")
    odds = over_odds if side == "OVER" else under_odds

    # Does Pinnacle confirm our direction?
    # If Pinnacle shows >52% for our side = confirms edge
    confirms = prob > 0.52
    fade_signal = prob < 0.46  # Pinnacle disagrees strongly

    if confirms:
        note = f"📌 Pinnacle confirms {side}: {prob:.1%} true prob (fair odds: {odds:+.0f})"
    elif fade_signal:
        note = f"⚠️ Pinnacle FADES {side}: {prob:.1%} true prob — sharp money disagrees"
    else:
        note = f"📌 Pinnacle neutral: {prob:.1%} true prob"

    return prob, confirms, note


def get_pinnacle_edge(model_prob, pinnacle_prob, side="OVER"):
    """
    Calculate edge vs Pinnacle as the benchmark.
    This is the OddsJam/Outlier methodology.
    positive = we have edge over Pinnacle's true line
    """
    if pinnacle_prob is None or model_prob is None:
        return None
    # Edge = our model prob - Pinnacle true prob
    # If positive, we think this is MORE likely than Pinnacle does
    return round(model_prob - pinnacle_prob, 4)


# =============================================================
# PLAYER LOOKUP ENGINE — H2H, Game Logs, Splits
# Powers the Player Lookup tab and H2H signal
# =============================================================

def fetch_player_id_bdl(player_name):
    """Search BallsDontLie for player ID by name."""
    if not BDL_API_KEY:
        return None
    cache_path = os.path.join(CACHE_DIR, f"bdl_pid_{normalize_name(player_name)}.pkl")
    if os.path.exists(cache_path):
        age_days = (time.time() - os.path.getmtime(cache_path)) / 86400
        if age_days < 7:
            with open(cache_path, "rb") as f:
                return pickle.load(f)
    try:
        r = requests.get(
            f"https://api.balldontlie.io/v1/players",
            headers={"Authorization": BDL_API_KEY},
            params={"search": player_name, "per_page": 5},
            timeout=10
        )
        if r.status_code == 200:
            data = r.json().get("data", [])
            if data:
                pid = data[0]["id"]
                with open(cache_path, "wb") as f:
                    pickle.dump(pid, f)
                return pid
    except (ValueError, KeyError, TypeError, AttributeError):
        pass
    return None


def fetch_player_game_logs(player_name, season=2025, last_n=15):
    """
    Fetch last N game logs for a player.
    Returns list of game dicts with pts, reb, ast, min, opponent, date, home/away.
    """
    if not BDL_API_KEY:
        return []
    cache_key = f"bdl_logs_{normalize_name(player_name)}_{season}"
    cache_path = os.path.join(CACHE_DIR, f"{cache_key}.pkl")
    if os.path.exists(cache_path):
        age_hours = (time.time() - os.path.getmtime(cache_path)) / 3600
        if age_hours < 4:
            with open(cache_path, "rb") as f:
                return pickle.load(f)

    pid = fetch_player_id_bdl(player_name)
    if not pid:
        return []

    try:
        r = requests.get(
            f"https://api.balldontlie.io/v1/stats",
            headers={"Authorization": BDL_API_KEY},
            params={
                "player_ids[]": pid,
                "seasons[]": season,
                "per_page": last_n,
                "sort_by": "date",
                "order": "desc"
            },
            timeout=15
        )
        if r.status_code != 200:
            return []

        games = r.json().get("data", [])
        logs = []
        for g in games:
            game = g.get("game", {})
            team = g.get("team", {})
            home_team_id = game.get("home_team_id")
            is_home = team.get("id") == home_team_id
            opp_id = game.get("visitor_team_id") if is_home else game.get("home_team_id")

            logs.append({
                "date": game.get("date", "")[:10],
                "home": is_home,
                "opponent_id": opp_id,
                "pts": g.get("pts", 0),
                "reb": g.get("reb", 0),
                "ast": g.get("ast", 0),
                "stl": g.get("stl", 0),
                "blk": g.get("blk", 0),
                "turnover": g.get("turnover", 0),
                "fg3m": g.get("fg3m", 0),
                "min": g.get("min", "0"),
                "pra": (g.get("pts",0) or 0) + (g.get("reb",0) or 0) + (g.get("ast",0) or 0),
            })

        if logs:
            with open(cache_path, "wb") as f:
                pickle.dump(logs, f)
        return logs

    except Exception as e:
        st.session_state.setdefault("errors", []).append({
            "time": datetime.now().strftime("%H:%M:%S"),
            "source": "fetch_player_game_logs",
            "error": str(e)[:100]
        })
        return []


def compute_h2h_hit_rate(game_logs, opponent_abbr, stat, line):
    """
    Compute H2H hit rate vs a specific opponent.
    Returns (hit_rate, games_played, sample_str)
    """
    stat_map = {
        "Points": "pts", "Rebounds": "reb", "Assists": "ast",
        "Steals": "stl", "Blocked Shots": "blk", "Turnovers": "turnover",
        "3-PT Made": "fg3m", "Pts+Reb+Ast": "pra",
    }
    stat_key = stat_map.get(stat, stat.lower()[:3])
    opp_games = [g for g in game_logs if str(g.get("opponent_id","")).lower() in opponent_abbr.lower()
                 or opponent_abbr.lower() in str(g.get("opponent_id","")).lower()]

    if not opp_games:
        return None, 0, "No H2H data"

    hits = sum(1 for g in opp_games if (g.get(stat_key) or 0) > line)
    rate = hits / len(opp_games)
    return rate, len(opp_games), f"{hits}/{len(opp_games)} vs this opponent"


def compute_home_away_splits(game_logs, stat, line):
    """Compute home vs away hit rates for a stat."""
    stat_map = {
        "Points": "pts", "Rebounds": "reb", "Assists": "ast",
        "Steals": "stl", "Blocked Shots": "blk", "Turnovers": "turnover",
        "3-PT Made": "fg3m", "Pts+Reb+Ast": "pra",
    }
    stat_key = stat_map.get(stat, "pts")

    home_games = [g for g in game_logs if g.get("home")]
    away_games = [g for g in game_logs if not g.get("home")]

    home_avg = sum(g.get(stat_key,0) or 0 for g in home_games) / len(home_games) if home_games else 0
    away_avg = sum(g.get(stat_key,0) or 0 for g in away_games) / len(away_games) if away_games else 0
    home_hit = sum(1 for g in home_games if (g.get(stat_key,0) or 0) > line) / len(home_games) if home_games else 0
    away_hit = sum(1 for g in away_games if (g.get(stat_key,0) or 0) > line) / len(away_games) if away_games else 0

    return {
        "home_avg": round(home_avg, 1),
        "away_avg": round(away_avg, 1),
        "home_hit_rate": home_hit,
        "away_hit_rate": away_hit,
        "home_games": len(home_games),
        "away_games": len(away_games),
    }
@st.cache_data(ttl=3600)
def fetch_dk_nba_draftgroup_id():
    """Find today's NBA classic draftGroupId from DraftKings."""
    cache_path = os.path.join(CACHE_DIR, "dk_draftgroup_nba.pkl")
    if os.path.exists(cache_path):
        age_mins = (time.time() - os.path.getmtime(cache_path)) / 60
        if age_mins < 120:
            with open(cache_path, "rb") as f:
                return pickle.load(f)
    try:
        r = requests.get(
            "https://www.draftkings.com/lobby/getcontests?sport=NBA",
            headers={**HEADERS, "Referer": "https://www.draftkings.com/"},
            timeout=10
        )
        if r.status_code != 200:
            return None
        contests = r.json().get("Contests", [])
        # Find Classic contest (contestTypeId=21 or name contains Classic)
        for c in contests:
            name = c.get("n", "").lower()
            if "classic" in name and c.get("dg"):
                dgid = c["dg"]
                with open(cache_path, "wb") as f:
                    pickle.dump(dgid, f)
                return dgid
        # Fallback: first contest with a draftGroupId
        for c in contests:
            if c.get("dg"):
                dgid = c["dg"]
                with open(cache_path, "wb") as f:
                    pickle.dump(dgid, f)
                return dgid
    except Exception as e:
        st.session_state.setdefault("errors", []).append({
            "time": datetime.now().strftime("%H:%M:%S"),
            "source": "fetch_dk_nba_draftgroup_id",
            "error": str(e)[:100]
        })
    return None



@st.cache_data(ttl=900)
def fetch_sleeper_props(sport):
    """
    Fetch player props from Sleeper DFS - free public API.
    Available in California. Returns props in standard format.
    """
    sport_map = {"NBA": "nba", "MLB": "mlb", "NFL": "nfl", "NHL": "nhl"}
    sport_key = sport_map.get(sport)
    if not sport_key:
        return []

    cache_path = os.path.join(CACHE_DIR, f"sleeper_props_{sport}.pkl")
    if os.path.exists(cache_path):
        age_mins = (time.time() - os.path.getmtime(cache_path)) / 60
        if age_mins < 90:
            with open(cache_path, "rb") as f:
                return pickle.load(f)

    try:
        # Sleeper projections endpoint
        url = f"https://api.sleeper.app/projections/{sport_key}/2025/1?season_type=regular&position[]=FLEX&position[]=QB&position[]=RB&position[]=WR&position[]=TE&position[]=K"
        r = requests.get(url, headers=HEADERS, timeout=15)
        if r.status_code != 200:
            return []

        data = r.json()
        props = []
        seen = set()

        # Sleeper returns projections, not explicit lines
        # We use projected stats as our own lines for comparison
        stat_map = {
            "pts_std": "Points", "rec_yd": "Receiving Yards",
            "rush_yd": "Rushing Yards", "pass_yd": "Passing Yards",
            "rec": "Receptions", "pts_half_ppr": "Fantasy Points",
        }
        for player_proj in data:
            if not isinstance(player_proj, dict):
                continue
            player_id = player_proj.get("player_id","")
            stats = player_proj.get("stats", {})
            player_info = player_proj.get("player", {})
            if not player_info:
                continue
            name = f"{player_info.get('first_name','')} {player_info.get('last_name','')}".strip()
            if not name:
                continue
            for stat_key, stat_name in stat_map.items():
                val = stats.get(stat_key)
                if val and float(val) > 0:
                    line = round(float(val) - 0.5, 1)
                    key = (sport, name, stat_name)
                    if key not in seen:
                        seen.add(key)
                        props.append({
                            "Player": name, "Prop": stat_name,
                            "Line": line, "Side": "OVER",
                            "Sport": sport, "source": "Sleeper",
                            "SleeperProjection": float(val)
                        })

        if props:
            with open(cache_path, "wb") as f:
                pickle.dump(props, f)
        return props

    except Exception as e:
        st.session_state.setdefault("errors", []).append({
            "time": datetime.now().strftime("%H:%M:%S"),
            "source": "fetch_sleeper_props",
            "error": str(e)[:100]
        })
        return []


def _fetch_parallel(fns: list) -> list:
    """Run multiple fetch functions in parallel threads, return results in order.
    Records per-source timing in st.session_state['fetch_timings'] for profiler UI.
    """
    from concurrent.futures import ThreadPoolExecutor, as_completed
    import time as _time
    results = [None] * len(fns)
    timings = {}
    def _timed(fn, idx):
        name = getattr(fn, '__name__', f'fn_{idx}').replace('_pf_','').replace('fetch_','')
        t0 = _time.time()
        try:
            result = fn()
            elapsed = round(_time.time() - t0, 2)
            timings[name] = {"time": elapsed, "status": "✅"}
            return result
        except Exception as e:
            elapsed = round(_time.time() - t0, 2)
            timings[name] = {"time": elapsed, "status": f"❌ {str(e)[:40]}"}
            return None
    with ThreadPoolExecutor(max_workers=min(len(fns), 8)) as ex:
        futures = {ex.submit(_timed, fn, i): i for i, fn in enumerate(fns)}
        for fut in as_completed(futures):
            idx = futures[fut]
            try:
                results[idx] = fut.result()
            except Exception:
                results[idx] = None
    # Store timings — merged with any existing from this session
    existing = st.session_state.get("fetch_timings", {})
    existing.update(timings)
    st.session_state["fetch_timings"] = existing
    return results



@st.cache_data(ttl=600)
def fetch_mlb_confirmed_lineups():
    """
    Fetch confirmed MLB batting lineups for today's games.
    Uses statsapi.mlb.com — same API as mlb averages, already trusted.
    
    Returns dict: {team_abbr: [player1, player2, ...]} in batting order.
    Lineup is "confirmed" when it comes from today's actual game feed.
    
    Why this matters: cleanup hitter scratches move HR/RBI props significantly.
    A confirmed lineup vs a projected lineup is a real betting edge.
    """
    try:
        today_str = date.today().strftime("%Y-%m-%d")
        schedule_url = f"https://statsapi.mlb.com/api/v1/schedule?sportId=1&date={today_str}&hydrate=lineups,probablePitcher"
        r = requests.get(schedule_url, timeout=10)
        if r.status_code != 200:
            return {}
        games = r.json().get("dates", [{}])[0].get("games", [])
        lineups = {}
        for game in games:
            game_id = game.get("gamePk")
            if not game_id:
                continue
            # Get lineups from game feed
            feed_url = f"https://statsapi.mlb.com/api/v1.1/game/{game_id}/feed/live?fields=gameData,liveData,boxscore,teams,batters,battingOrder,players,fullName,currentTeam,abbreviation"
            try:
                rf = requests.get(feed_url, timeout=8)
                if rf.status_code != 200:
                    continue
                feed = rf.json()
                # Extract home/away batting orders
                for side in ("home", "away"):
                    team_data = feed.get("liveData",{}).get("boxscore",{}).get("teams",{}).get(side,{})
                    batting_order = team_data.get("battingOrder", [])
                    players = team_data.get("players", {})
                    team_abbr = feed.get("gameData",{}).get("teams",{}).get(side,{}).get("abbreviation","")
                    if batting_order and team_abbr:
                        lineup = []
                        for pid in batting_order:
                            player_key = f"ID{pid}"
                            pdata = players.get(player_key, {})
                            pname = pdata.get("person",{}).get("fullName","")
                            pos = pdata.get("position",{}).get("abbreviation","")
                            if pname:
                                lineup.append({"name": pname, "position": pos, "batting_order": len(lineup)+1})
                        if lineup:
                            lineups[team_abbr] = {
                                "players": lineup,
                                "confirmed": len(lineup) >= 9,
                                "source": "MLB Stats API",
                                "fetched_at": datetime.now().strftime("%H:%M"),
                            }
            except (ValueError, KeyError, TypeError, AttributeError):
                continue
        return lineups
    except (requests.RequestException, ValueError, KeyError):
        return {}
